arguments.prompt:
You are implementing a Blazor Web App for a logistics shipment tracker. The project is already scaffolded at `/tmp/sv-8a993bb8170e473cbe4eaeb0e9c5fb57/ShipmentTracker/` with Interactive Auto, global interactivity, and Individual auth.

The project structure:
- `ShipmentTracker/` (server project) - hosts the app, has EF Core + Identity
- `ShipmentTracker.Client/` (client project) - interactive components go here

Key architecture rule: Interactive components in .Client cannot access DbContext directly. Use interface + two implementations pattern:
1. Interface in .Client project
2. HttpClient implementation in .Client
3. Direct DB implementation in server
4. Minimal API endpoints in server

## Tasks

### 1. Remove template pages
Delete these files:
- `ShipmentTracker.Client/Pages/Counter.razor`
- `ShipmentTracker.Client/Pages/Weather.razor`

### 2. Create shared models in the .Client project

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 3. Create service interface in .Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 4. Create HttpClient implementation in .Client project

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 5. Register HttpClient and service in Client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient("ServerAPI", client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
builder.Services.AddScoped(sp =>
    sp.GetRequiredService<IHttpClientFactory>().CreateClient("ServerAPI"));
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

### 6. Create EF Core entity and DbContext extension in server project

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using System.ComponentModel.DataAnnotations;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;

    public Shipment ToModel() => new()
    {
        Id = Id,
        TrackingNumber = TrackingNumber,
        Origin = Origin,
        Destination = Destination,
        Status = Status,
        CreatedDate = CreatedDate,
        EstimatedDelivery = EstimatedDelivery,
        CustomerEmail = CustomerEmail,
        Description = Description
    };

    public static ShipmentEntity FromModel(Shipment model) => new()
    {
        Id = model.Id,
        TrackingNumber = model.TrackingNumber,
        Origin = model.Origin,
        Destination = model.Destination,
        Status = model.Status,
        CreatedDate = model.CreatedDate,
        EstimatedDelivery = model.EstimatedDelivery,
        CustomerEmail = model.CustomerEmail,
        Description = model.Description
    };
}
```

Add a DbSet to the existing `ApplicationDbContext`. Find the file at `ShipmentTracker/Data/ApplicationDbContext.cs` and add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

### 7. Create server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => s.ToModel())
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity?.ToModel();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = ShipmentEntity.FromModel(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        entity.Status = ShipmentStatus.Pending;

        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}
```

### 8. Create API endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(s => s.ToModel()));
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return entity is null ? Results.NotFound() : Results.Ok(entity.ToModel());
        }).AllowAnonymous();

        group.MapPost("", async (Shipment shipment, ApplicationDbContext db) =>
        {
            var entity = ShipmentEntity.FromModel(shipment);
            entity.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
            entity.CreatedDate = DateTime.UtcNow;
            entity.Status = ShipmentStatus.Pending;

            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{entity.Id}", entity.ToModel());
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            await db.SaveChangesAsync();
            return Results.Ok(entity.ToModel());
        });
    }
}
```

### 9. Register services and endpoints in server Program.cs

Edit `ShipmentTracker/Program.cs`:
- Add `using ShipmentTracker.Client.Services;` and `using ShipmentTracker.Services;` and `using ShipmentTracker.Endpoints;` at the top
- After `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();` add:
  ```csharp
  builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
  ```
- Before `app.Run();` add:
  ```csharp
  app.MapShipmentEndpoints();
  ```

### 10. Create the Dispatcher page

Create `ShipmentTracker.Client/Pages/Dispatcher.razor`:
```razor
@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

@if (_loading)
{
    <p>Loading shipments...</p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            @(_showCreate ? "Cancel" : "New Shipment")
        </button>
    </div>

    @if (_showCreate)
    {
        <div class="card mb-4 p-3">
            <h4>Create Shipment</h4>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="_newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="_newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="_newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="_newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-9">
                    <input class="form-control" placeholder="Description" @bind="_newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success w-100" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    }

    @if (!_shipments.Any())
    {
        <p>No shipments found.</p>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Created</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in _shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CreatedDate.ToShortDateString()</td>
