```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => s.ToModel())
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity?.ToModel();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = ShipmentEntity.FromModel(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        entity.Status = ShipmentStatus.Pending;

        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}
```

### 8. Create API endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(s => s.ToModel()));
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return entity is null ? Results.NotFound() : Results.Ok(entity.ToModel());
        }).AllowAnonymous();

        group.MapPost("", async (Shipment shipment, ApplicationDbContext db) =>
        {
            var entity = ShipmentEntity.FromModel(shipment);
            entity.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
            entity.CreatedDate = DateTime.UtcNow;
            entity.Status = ShipmentStatus.Pending;

            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{entity.Id}", entity.ToModel());
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            await db.SaveChangesAsync();
            return Results.Ok(entity.ToModel());
        });
    }
}
```

