namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}

using System.ComponentModel.DataAnnotations;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;

    public Shipment ToModel() => new()
    {
        Id = Id,
        TrackingNumber = TrackingNumber,
        Origin = Origin,
        Destination = Destination,
        Status = Status,
        CreatedDate = CreatedDate,
        EstimatedDelivery = EstimatedDelivery,
        CustomerEmail = CustomerEmail,
        Description = Description
    };

    public static ShipmentEntity FromModel(Shipment model) => new()
    {
        Id = model.Id,
        TrackingNumber = model.TrackingNumber,
        Origin = model.Origin,
        Destination = model.Destination,
        Status = model.Status,
        CreatedDate = model.CreatedDate,
        EstimatedDelivery = model.EstimatedDelivery,
        CustomerEmail = model.CustomerEmail,
        Description = model.Description
    };
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => s.ToModel())
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity?.ToModel();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = ShipmentEntity.FromModel(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        entity.Status = ShipmentStatus.Pending;

        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(s => s.ToModel()));
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return entity is null ? Results.NotFound() : Results.Ok(entity.ToModel());
        }).AllowAnonymous();

        group.MapPost("", async (Shipment shipment, ApplicationDbContext db) =>
        {
            var entity = ShipmentEntity.FromModel(shipment);
            entity.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
            entity.CreatedDate = DateTime.UtcNow;
            entity.Status = ShipmentStatus.Pending;

            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{entity.Id}", entity.ToModel());
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            await db.SaveChangesAsync();
            return Results.Ok(entity.ToModel());
        });
    }
}

