using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => s.ToModel())
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity?.ToModel();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = ShipmentEntity.FromModel(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        entity.Status = ShipmentStatus.Pending;

        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await db.SaveChangesAsync();
        return entity.ToModel();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}
```

### 8. Create API endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(s => s.ToModel()));
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return entity is null ? Results.NotFound() : Results.Ok(entity.ToModel());
        }).AllowAnonymous();

        group.MapPost("", async (Shipment shipment, ApplicationDbContext db) =>
        {
            var entity = ShipmentEntity.FromModel(shipment);
            entity.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
            entity.CreatedDate = DateTime.UtcNow;
            entity.Status = ShipmentStatus.Pending;

            db.Shipments.Add(entity);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{entity.Id}", entity.ToModel());
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            await db.SaveChangesAsync();
            return Results.Ok(entity.ToModel());
        });
    }
}
```

### 9. Register services and endpoints in server Program.cs

Edit `ShipmentTracker/Program.cs`:
- Add `using ShipmentTracker.Client.Services;` and `using ShipmentTracker.Services;` and `using ShipmentTracker.Endpoints;` at the top
- After `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();` add:
  ```csharp
  builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
  ```
- Before `app.Run();` add:
  ```csharp
  app.MapShipmentEndpoints();
  ```

### 10. Create the Dispatcher page

Create `ShipmentTracker.Client/Pages/Dispatcher.razor`:
```razor
@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

@if (_loading)
{
    <p>Loading shipments...</p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            @(_showCreate ? "Cancel" : "New Shipment")
        </button>
    </div>

    @if (_showCreate)
    {
        <div class="card mb-4 p-3">
            <h4>Create Shipment</h4>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="_newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="_newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="_newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="_newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-9">
                    <input class="form-control" placeholder="Description" @bind="_newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success w-100" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    }

    @if (!_shipments.Any())
    {
        <p>No shipments found.</p>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Created</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in _shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CreatedDate.ToShortDateString()</td>
                        <td>@(shipment.EstimatedDelivery?.ToShortDateString() ?? "N/A")</td>
                        <td>
                            <select class="form-select form-select-sm" value="@shipment.Status"
                                    @onchange="e => UpdateStatus(shipment.Id, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    private List<Shipment> _shipments = [];
    private bool _loading = true;
    private bool _showCreate;
    private Shipment _newShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        _loading = true;
        _shipments = await ShipmentService.GetAllShipmentsAsync();
        _loading = false;
    }

    private void ShowCreateForm() => _showCreate = !_showCreate;

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(_newShipment);
        _newShipment = new();
        _showCreate = false;
        await LoadShipments();
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            await LoadShipments();
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}
```

### 11. Create the Track Shipment page (customer-facing)

Create `ShipmentTracker.Client/Pages/TrackShipment.razor`:
```razor
@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., SHP-20260524-12345)"
                   @bind="_trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (_searching)
{
    <p>Searching...</p>
}
else if (_searched && _shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@_searchedNumber</strong>.
    </div>
}
else if (_shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h4 class="mb-0">Shipment <code>@_shipment.TrackingNumber</code></h4>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge bg-@GetStatusColor(_shipment.Status) fs-6">@_shipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@_shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@_shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@_shipment.CreatedDate.ToShortDateString()</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (_shipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@_shipment.EstimatedDelivery.Value.ToShortDateString()</strong>
                            }
                            else
                            {
                                <span class="text-muted">Not yet determined</span>
                            }
                        </dd>

                        <dt>Description</dt>
                        <dd>@(string.IsNullOrEmpty(_shipment.Description) ? "N/A" : _shipment.Description)</dd>
                    </dl>
                </div>
            </div>

            @if (_shipment.Status == ShipmentStatus.Delivered)
            {
                <div class="alert alert-success mt-3">
                    ✓ This shipment has been delivered.
                </div>
            }
            else if (_shipment.Status == ShipmentStatus.Delayed)
            {
                <div class="alert alert-danger mt-3">
                    ⚠ This shipment is currently delayed. We apologize for the inconvenience.
                </div>
            }
        </div>
    </div>
}

@code {
    private string _trackingNumber = string.Empty;
    private string _searchedNumber = string.Empty;
    private Shipment? _shipment;
    private bool _searching;
    private bool _searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(_trackingNumber)) return;

        _searching = true;
        _searched = false;
        _shipment = null;
        StateHasChanged();

        _searchedNumber = _trackingNumber.Trim();
        _shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(_searchedNumber);
        _searching = false;
        _searched = true;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}
```

